SELECT [Reserv__Assign_ Link].[Reserv__Assign_ Type], [Reserv__Assign_ Link].[Sales Document No_] AS OrdineNumero, [Reserv__Assign_ Link].[Sales Line No_] AS OrdineRiga, [Reserv__Assign_ Link].[Source Document No_], [Reserv__Assign_ Link].[Source Line No_], Val([Reserved_Assigned Quantity]) AS assortmentQty, [Reserv__Assign_ Link].Type, [Reserv__Assign_ Link].[Source Type], Val([Reserved_Assigned Quantity])*[assortmentquantity] AS pairsQty, "PREN-GIA" AS statusRiga, [Reserv__Assign_ Link].[Selling Season Code] AS [Season Code], [Reserv__Assign_ Link].[Date Reservation], [Sales Header].[Location Code] AS SalesLocation
FROM (([Reserv__Assign_ Link] LEFT JOIN AssortimentiQuantita ON ([Reserv__Assign_ Link].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Reserv__Assign_ Link].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])) LEFT JOIN Item ON [Reserv__Assign_ Link].No_ = Item.No_) LEFT JOIN [Sales Header] ON [Reserv__Assign_ Link].[Sales Document No_] = [Sales Header].No_
WHERE ((([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1) AND ((Val([Reserved_Assigned Quantity]))<>0) AND (([Reserv__Assign_ Link].Type)=20) AND (([Reserv__Assign_ Link].[Source Type])=0) AND (([Reserv__Assign_ Link].[Selling Season Code])=[forms]![principale]![filtroStagioneprenotazioni]));

